import * as fs from "node:fs";
import * as path from "node:path";
import archiver from "archiver";

function isInsideDir(parent: string, child: string): boolean {
  const rel = path.relative(parent, child);
  return !rel.startsWith("..") && !path.isAbsolute(rel);
}

export async function packageExtension(
  dir: string | undefined,
  outputPath: string | undefined,
  include: string[] | undefined,
): Promise<void> {
  const extensionDir = path.resolve(dir || process.cwd());

  const manifestPath = path.join(extensionDir, "manifest.json");
  if (!fs.existsSync(manifestPath)) {
    console.error(`No manifest.json found in ${extensionDir}`);
    process.exit(1);
  }

  const manifest = JSON.parse(fs.readFileSync(manifestPath, "utf-8"));
  const entryFile = manifest.entry;
  if (!entryFile) {
    console.error("manifest.json is missing the 'entry' field");
    process.exit(1);
  }

  const entryPath = path.join(extensionDir, entryFile);
  if (!fs.existsSync(entryPath)) {
    console.error(`Entry file not found: ${entryPath}`);
    console.error("Did you build the extension first?");
    process.exit(1);
  }

  for (const inc of include || []) {
    if (path.isAbsolute(inc)) {
      console.error(`Included path must be relative: ${inc}`);
      process.exit(1);
    }
    const resolved = path.resolve(extensionDir, inc);
    if (!isInsideDir(extensionDir, resolved)) {
      console.error(`Included path escapes extension directory: ${inc}`);
      process.exit(1);
    }
    if (!fs.existsSync(resolved)) {
      console.error(`Included path not found: ${inc}`);
      process.exit(1);
    }
  }

  const name = (manifest.name || path.basename(extensionDir)).replace(
    /\s+/gu,
    "-",
  );
  const version = manifest.version || "0.0.0";
  const ablxName = `${name}-${version}.ablx`;
  const ablxPath = outputPath || path.join(extensionDir, ablxName);

  const output = fs.createWriteStream(ablxPath);
  const archive = archiver("zip", { zlib: { level: 9 } });

  const done = new Promise<void>((resolve, reject) => {
    output.on("close", resolve);
    archive.on("error", reject);
  });

  archive.pipe(output);
  archive.file(manifestPath, { name: "manifest.json" });
  archive.file(entryPath, { name: entryFile });

  for (const inc of include || []) {
    const resolved = path.resolve(extensionDir, inc);
    const stat = fs.statSync(resolved);
    if (stat.isDirectory()) {
      archive.directory(resolved, inc);
    } else {
      archive.file(resolved, { name: inc });
    }
  }

  await archive.finalize();
  await done;

  console.log(ablxPath);
}
