import * as fs from "node:fs";
import * as path from "node:path";
import { createRequire } from "node:module";

import { spawn } from "node:child_process";

export const NODE_MODULE_FILE = "ExtensionHostNodeModule.node";

export function resolveExtensionHostDir(livePath: string): string {
  const appPath = livePath.replace(/[\\/]+$/u, "");

  if (!fs.existsSync(appPath)) {
    throw new Error(`Path not found: ${appPath}`);
  }

  // Direct path to the .node module
  if (appPath.endsWith(".node")) {
    return path.dirname(appPath);
  }

  // Windows: <program-dir>/Ableton Live.exe
  if (appPath.endsWith(".exe")) {
    return path.join(path.dirname(appPath), "ExtensionHost");
  }

  // macOS: Live.app bundle
  if (appPath.endsWith(".app")) {
    return path.join(appPath, "Contents", "Helpers", "ExtensionHost");
  }

  // Windows install root: <install-root>/Program/ExtensionHost
  const winExtHost = path.join(appPath, "Program", "ExtensionHost");
  if (fs.existsSync(path.join(winExtHost, NODE_MODULE_FILE))) {
    return winExtHost;
  }

  // Directory containing the node module directly (e.g. a debug build output)
  const stat = fs.statSync(appPath);
  if (
    stat.isDirectory() &&
    fs.existsSync(path.join(appPath, NODE_MODULE_FILE))
  ) {
    return appPath;
  }

  throw new Error(
    `Invalid Ableton Live path: ${livePath}\n` +
      "Expected Ableton Live (.app on macOS, .exe on Windows), " +
      "a directory containing ExtensionHostNodeModule.node, " +
      "or a direct path to ExtensionHostNodeModule.node",
  );
}

function findExtensionHost(livePath: string): {
  nodeExecutable: string;
  nodeModule: string;
} {
  const extensionHostDir = resolveExtensionHostDir(livePath);

  const nodeModule = path.join(extensionHostDir, NODE_MODULE_FILE);
  const nodeExeName = process.platform === "win32" ? "node.exe" : "node";
  const bundledNode = path.join(extensionHostDir, nodeExeName);
  // Fall back to the running node executable if the host dir doesn't ship one
  // (e.g. when pointing at a debug build of the module).
  const nodeExecutable = fs.existsSync(bundledNode)
    ? bundledNode
    : process.execPath;

  if (!fs.existsSync(nodeModule)) {
    throw new Error(
      `${NODE_MODULE_FILE} not found at: ${nodeModule}\n` +
        "Make sure you're using a version of Ableton Live that supports extensions.",
    );
  }

  return { nodeExecutable, nodeModule };
}

export interface RunOptions {
  live: string;
  storageDirectory?: string;
  tempDirectory?: string;
  inspect?: boolean;
}

export function buildExtensionObject(
  extensionPath: string,
  options: RunOptions,
): Record<string, string> {
  const toForwardSlash = (str: string) => str.replace(/\\/gu, "/");

  const extensionObject: Record<string, string> = {
    path: toForwardSlash(extensionPath),
  };
  if (options.storageDirectory) {
    extensionObject.storageDirectory = toForwardSlash(
      path.resolve(options.storageDirectory),
    );
  }
  if (options.tempDirectory) {
    extensionObject.tempDirectory = toForwardSlash(
      path.resolve(options.tempDirectory),
    );
  }
  return extensionObject;
}

export function runExtension(
  extensionDir: string | undefined,
  options: RunOptions,
): void {
  const { nodeExecutable, nodeModule } = findExtensionHost(options.live);

  const extensionPath = path.resolve(extensionDir || process.cwd());

  const pkgPath = path.join(extensionPath, "package.json");
  if (!fs.existsSync(pkgPath)) {
    console.error(`No package.json found at: ${extensionPath}`);
    process.exit(1);
  }

  console.log("Starting Extension Host...");
  console.log(`  Extension: ${extensionPath}`);
  console.log(`  Live: ${options.live}`);
  console.log();

  const extensionObject = buildExtensionObject(extensionPath, options);

  // When --inspect, load in-process so VS Code's launch debugger attaches
  // to the correct process. Without it, spawn a child (avoids --inspect-brk
  // hanging when no debugger is attached).
  if (options.inspect) {
    // The CLI is ESM, but the host's initialize() evaluates the user's
    // CJS-bundled extension which references the global `require`. Expose
    // it on globalThis before the host runs anything.
    const require = createRequire(import.meta.url);
    (globalThis as unknown as { require: typeof require }).require = require;
    require(nodeModule).initialize({ extensions: [extensionObject] });
    return;
  }

  const command = `require('${nodeModule.replace(/\\/gu, "/")}').initialize(${JSON.stringify({ extensions: [extensionObject] })});`;

  const nodeProcess = spawn(nodeExecutable, ["-e", command], {
    cwd: process.cwd(),
    stdio: "inherit",
  });

  nodeProcess.on("exit", (code) => {
    process.exit(code || 0);
  });
}
